public void clicked()
{
    FormRun formRun = this.formRun();
    FormDataSource purchTableDs = formRun.dataSource(formDataSourceStr(PurchTable, PurchTable));
    PurchTable purchTable = purchTableDs.cursor();

    if (purchTable.DocumentState != VersioningDocumentState::Confirmed)
    {
        warning("Purchase order must be in Confirmed state to open Grain Receipt Note.");
        return;
    }
}
